SELECT i.inquiry_idx, i.member_idx, i.category, i.title, i.content, i.file_path, i.status, i.created_at, i.updated_at, m.member_nickname, m.member_email FROM inquiry i LEFT JOIN member m ON i.member_idx = m.member_idx WHERE i.status != '삭제'
AND i.member_idx = #{member_idx}
AND i.category = #{category}
AND i.title LIKE CONCAT('%', #{searchValue}, '%')
AND i.content LIKE CONCAT('%', #{searchValue}, '%')
AND i.category LIKE CONCAT('%', #{searchValue}, '%')
ORDER BY i.created_at DESC LIMIT #{begin}, #{end}

SELECT COUNT(*) FROM inquiry i WHERE i.status != '삭제'
AND i.member_idx = #{member_idx}
AND i.category = #{category}
AND i.title LIKE CONCAT('%', #{searchValue}, '%')
AND i.content LIKE CONCAT('%', #{searchValue}, '%')
AND i.category LIKE CONCAT('%', #{searchValue}, '%')

SELECT *
FROM inquiry
WHERE created_at BETWEEN '#{begin_date}' AND '#{end_date}';
